var e=[{id:`L3_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`역시 나이엘이야! 인정사정 없이 몰아붙이고 있어!`,JPN:`さすがナイエル！　容赦なく追い込んでる！`,ENG:`That's so like Naielle. Look at the way she's pushing her!`,TWN:`不愧是奈爾！出手毫不留情呢！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`STUDENT_EXTRA_B_TWINTAIL`,text:{KOREA:`굉장해! 상대가 초등부 학생이라도 자비가 없지!`,JPN:`すごい！　相手が初等部でも容赦しない！`,ENG:`Incredible! She shows mercy to no one—not even an elementary school kid!`,TWN:`太厲害了！哪怕對手是小學部的學生也毫不手軟！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`으으......`,JPN:`うう……`,ENG:`Ugh...`,TWN:`嗚嗚……`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`호오, 꽤 하는걸? 하지만 얼마나 버틸 수 있을까?`,JPN:`へえ、やるじゃない！　でもいつまで耐えられるのかしら？`,ENG:`Ooo, you're pretty good. Let's see how long you last.`,TWN:`呼噢，有兩下子？我倒要看看你能撐多長時間？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`뭐야, 이 꼬맹이! 보기보다 힘이 엄청 세잖아?!`,JPN:`なんだこのチビ！　見た目よりすごい力持ちじゃん！？`,ENG:`Geez, this kid! She's much stronger than she looks!`,TWN:`哎呦，這個小不點！力氣比看起來大很多啊？！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`말도 안 돼! 초등부에 이런 녀석이 있다는 얘기 들은 적 없는데?!`,JPN:`ありえない！　初等部にこんな子がいるなんて話は聞いてない！！`,ENG:`This doesn't make sense! I've never heard of anyone so strong in elementary school.`,TWN:`不可能！我沒聽說小學部有這種傢伙啊？！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`괜히 힘 대결로 들어갔어! 이럴 줄 알았으면 처음부터 그냥 기술로 몰아붙이는 건데!`,JPN:`力勝負にするべきじゃなかった！　最初から技で追い詰めればよかったわ！`,ENG:`Why did I decide to use physical strength against her? I should have pressured her with my skills to begin with!`,TWN:`用力量對決沒什麼用了！早知道一開始我就應該直接靠技能碾壓！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`읏......!`,JPN:`うっ……！`,ENG:`Ngh!`,TWN:`呃……！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`팔이 떨려...... 역시 그만둘래......`,JPN:`腕が震える……やっぱりやめる……`,ENG:`My hands are shaking... I'm just going to give up...`,TWN:`手臂抖的很厲害……不行，我要放棄……`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`자! 이대로 얌전히 떨어지라고!`,JPN:`さあ！　これで大人しく落ちなさい！`,ENG:`Now, be a good girl and get out of the ring!`,TWN:`好！就這樣安靜地掉下去吧！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`GIRL_NPC_NULL_Q`,text:{KOREA:`......케이시! 힘내!!`,JPN:`……ケイシー！　頑張って！！`,ENG:`... Kaci! Bear up!`,TWN:`……卡西！加油！！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`POLEARM_JUNIOR_NULL_NULL`,text:{KOREA:`앗......!`,JPN:`あっ……！`,ENG:`Ah!`,TWN:`啊……！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`어...... 얼레? 내가 구석에 몰렸는데?`,JPN:`あ……あれ？　私が端っこに！？`,ENG:`Err? What happened? How did I get myself cornered?`,TWN:`哎……哎呦？我被逼到角落裡了？`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SURPRISE`},C:{char_id:`POLEARM_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`궁지에 몰렸던 청팀 선수! 순식간에 홍팀 선수 뒤로 파고들어 밀어냅니다!`,JPN:`窮地に追い込まれていた青組選手！　あっという間に赤組選手の後ろに突っ込んで押し出します！`,ENG:`The Blue Team player escapes from danger and quickly goes behind her opponent, pushing her!`,TWN:`被逼入絕境的藍隊選手！一瞬間跑到了紅隊選手背後，將紅隊選手推了下去！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HARIM_REBBIT_SPORTS_BG`,face:`UNIT_SURPRISE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`HARIM_REBBIT_SPORTS_BG`,text:{KOREA:`나이엘 선수, 안타깝게도 장외 실격이네요!`,JPN:`ナイエル選手、残念ながら場外になり失格です！`,ENG:`Naielle is out of the ring! She's been disqualified!`,TWN:`很遺憾，奈爾選手掉到了場外失去了資格！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HARIM_REBBIT_SPORTS_BG`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};